//! Runtime helper functions for native Rust code generated by `generation.rs`.
//!
//! The bytecode interpreter implements these operations as opcodes that read
//! parameters from the bytecode stream and manipulate the stack.  Generated
//! native code calls these wrapper functions directly with explicit arguments.
//!
//! **Interpreter safety:** This module is purely additive — it does not modify
//! any interpreter code path.  It only re-exposes `Stores` methods with the
//! signatures that generated code expects.

#![allow(non_snake_case)]
#![allow(clippy::cast_possible_truncation)]
#![allow(clippy::cast_sign_loss)]
#![allow(clippy::doc_markdown)]

use crate::database::{ShowDb, Stores};
use crate::keys::{Content, DbRef, Key};
use crate::ops;
use crate::tree;
use crate::vector;
use std::fs::{File, OpenOptions};
use std::io::{Read, Seek, SeekFrom, Write as _};

/// Allocate a database root record for the given type.
/// The generated code calls this as `OpDatabase(stores, var, tp)` where `var` is
/// passed by value (DbRef).  The function allocates into the store referenced by
/// `db`, then returns the updated DbRef.
/// Bytecode equivalent: `OpDatabase` in `src/state/io.rs:319`.
pub fn OpDatabase(stores: &mut Stores, mut db: DbRef, db_tp: i32) -> DbRef {
    let db_tp = db_tp as u16;
    let size = stores.size(db_tp);
    stores.clear(&db);
    let r = stores.claim(&db, u32::from(size));
    stores.store_mut(&r).set_int(r.rec, 4, i32::from(db_tp));
    stores.set_default_value(db_tp, &r);
    db.store_nr = r.store_nr;
    db.rec = 1;
    db.pos = 8;
    db
}

/// Create a new record element inside a vector/sorted/index collection.
/// Returns a `DbRef` pointing to the new element with default field values.
/// Bytecode equivalent: `OpNewRecord` in `src/state/io.rs:336`.
pub fn OpNewRecord(stores: &mut Stores, data: DbRef, parent_tp: i32, fld: i32) -> DbRef {
    let parent_tp = parent_tp as u16;
    let fld = fld as u16;
    let new_value = stores.record_new(&data, parent_tp, fld);
    stores.set_default_value(
        if fld == u16::MAX {
            stores.content(parent_tp)
        } else {
            stores.content(stores.field_type(parent_tp, fld))
        },
        &new_value,
    );
    new_value
}

/// Finalize a record after its fields have been assigned.
/// For sorted/index collections this inserts the record at the correct position.
/// Bytecode equivalent: `OpFinishRecord` in `src/state/io.rs:772`.
pub fn OpFinishRecord(stores: &mut Stores, data: DbRef, record: DbRef, parent_tp: i32, fld: i32) {
    stores.record_finish(&data, &record, parent_tp as u16, fld as u16);
}

/// Free a database reference.  Closes any associated file handle first.
/// Bytecode equivalent: `OpFreeRef` in `src/state/io.rs:262`.
pub fn OpFreeRef(stores: &mut Stores, db: DbRef) {
    if db.rec != 0
        && let Some(&file_type) = stores.names.get("File")
    {
        let stored_type = stores.store(&db).get_int(db.rec, 4) as u16;
        if stored_type == file_type {
            let file_ref = stores.store(&db).get_int(db.rec, db.pos + 28);
            if file_ref != i32::MIN && (file_ref as usize) < stores.files.len() {
                stores.files[file_ref as usize] = None;
            }
        }
    }
    stores.free(&db);
}

/// Format a database record as text and append it to the output string.
/// Bytecode equivalent: `OpFormatDatabase` in `src/state/io.rs:278`.
pub fn OpFormatDatabase(
    stores: &mut Stores,
    output: &mut String,
    record: DbRef,
    db_tp: i32,
    db_format: i32,
) {
    let mut s = String::new();
    ShowDb {
        stores,
        store: record.store_nr,
        rec: record.rec,
        pos: record.pos,
        known_type: db_tp as u16,
        pretty: db_format & 1 > 0,
        json: db_format & 2 > 0,
    }
    .write(&mut s, 0);
    output.push_str(&s);
}

/// Look up a record in a collection by key values.
/// Bytecode equivalent: `OpGetRecord` in `src/state/io.rs:353`.
pub fn OpGetRecord(
    stores: &mut Stores,
    data: DbRef,
    db_tp: i32,
    key: &[crate::keys::Content],
) -> DbRef {
    if data.rec == 0 {
        DbRef {
            store_nr: data.store_nr,
            rec: 0,
            pos: 0,
        }
    } else {
        stores.find(&data, db_tp as u16, key)
    }
}

/// Extract a substring from a text value.
/// Bytecode equivalent: `OpGetTextSub` in `src/fill.rs`.
#[must_use]
pub fn OpGetTextSub(text: &str, from: i32, till: i32) -> &str {
    #![allow(clippy::cast_possible_wrap)]
    let len = text.len() as i32;
    let f = from.max(0).min(len) as usize;
    // Negative `till` counts backwards from the end (e.g., -1 means len-1).
    let t = if till < 0 { (len + till).max(0).min(len) } else { till.min(len) } as usize;
    if f >= t { "" } else { &text[f..t] }
}

/// Return the byte size of a database record's type.
/// Bytecode equivalent: `OpSizeofRef` in `src/state/io.rs:290`.
#[must_use]
pub fn OpSizeofRef(stores: &Stores, db: DbRef) -> i32 {
    if db.rec == 0 {
        0
    } else {
        let tp = stores.store(&db).get_int(db.rec, 4) as u16;
        i32::from(stores.size(tp))
    }
}

/// Parse a text representation into a database record.
/// Bytecode equivalent: `State::db_from_text` in `src/state/io.rs:780`.
#[must_use]
pub fn db_from_text(stores: &mut Stores, val: &str, db_tp: i32) -> DbRef {
    let db_tp = db_tp as u16;
    let db = stores.database(8);
    let into = DbRef {
        store_nr: db.store_nr,
        rec: db.rec,
        pos: 8,
    };
    stores.set_default_value(db_tp, &into);
    let mut pos = 0;
    if stores.parsing(val, &mut pos, db_tp, db_tp, u16::MAX, &into) {
        into
    } else {
        DbRef {
            store_nr: db.store_nr,
            rec: 0,
            pos: 0,
        }
    }
}

/// Deep-copy a database record: copies the raw bytes and duplicates
/// all owned sub-structures (text fields, vectors, etc.).
/// Bytecode equivalent: `State::copy_record` in `src/state/io.rs:697`.
pub fn OpCopyRecord(stores: &mut Stores, data: DbRef, to: DbRef, tp: i32) {
    let tp = tp as u16;
    let size = u32::from(stores.size(tp));
    stores.copy_block(&data, &to, size);
    stores.copy_claims(&data, &to, tp);
}

/// Sort a vector in-place using the element type's natural ordering.
/// Bytecode equivalent: `sort_vector` in `src/fill.rs:1835`.
pub fn OpSortVector(stores: &mut Stores, data: DbRef, db_tp: i32) {
    let db_tp = db_tp as u16;
    let elem_size = stores.size(db_tp);
    let is_float = db_tp == 2 || db_tp == 3;
    vector::sort_vector(&data, elem_size, is_float, &mut stores.allocations);
}

/// Insert a new default-valued element at `index` in a vector, shifting later elements right.
/// Returns a `DbRef` pointing to the newly inserted element.
/// Bytecode equivalent: `State::insert_vector` in `src/state/io.rs:819`.
pub fn OpInsertVector(
    stores: &mut Stores,
    data: DbRef,
    size: i32,
    index: i32,
    db_tp: i32,
) -> DbRef {
    let new_value = vector::insert_vector(&data, size as u32, index, &mut stores.allocations);
    stores.set_default_value(db_tp as u16, &new_value);
    new_value
}

/// Return the UTF-8 byte length of a character (encoded as `i32` in loft).
/// Returns 0 for the null character sentinel.
/// Bytecode equivalent: `State::length_character` in `src/state/text.rs:54`.
#[must_use]
pub fn OpLengthCharacter(_stores: &mut Stores, c: i32) -> i32 {
    let ch = ops::to_char(c);
    if ch == '\0' {
        0
    } else {
        i32::try_from(ch.len_utf8()).unwrap_or(0)
    }
}

/// Pack a (current-position, finish) pair into a single i64 iterator state.
/// High 32 bits = finish; low 32 bits = cur.
/// `finish == u32::MAX` signals that iteration is complete.
fn pack_iter(cur: u32, finish: u32) -> i64 {
    ((u64::from(finish) << 32) | u64::from(cur)).cast_signed()
}

/// Build a minimal DbRef pointing at record `rec` with field offset `pos`.
fn iter_ref(data: &DbRef, rec: u32, pos: u16) -> DbRef {
    DbRef {
        store_nr: data.store_nr,
        rec,
        pos: u32::from(pos),
    }
}

/// Initialize a sorted/index iterator state and return it as a packed `i64`.
///
/// `on` encodes collection type and flags:
/// - bits 0–5: collection type (1 = red-black tree / index, 2 = sorted vector)
/// - bit 6: reverse iteration
/// - bit 7: inclusive end (if clear, end is exclusive)
///
/// `arg` is the element size in bytes (sorted) or the tree-fields offset (index).
/// `keys` describes the key fields in the collection type.
/// `from` / `till` are the from/till key values; empty slices mean start/end of collection.
///
/// The returned `i64` is consumed by [`OpStep`].
/// Bytecode equivalent: `State::iterate` in `src/state/io.rs`.
#[must_use]
pub fn OpIterate(
    stores: &Stores,
    data: DbRef,
    on: i32,
    arg: i32,
    keys: &[Key],
    from: &[Content],
    till: &[Content],
) -> i64 {
    if data.rec == 0 {
        return pack_iter(u32::MAX, u32::MAX);
    }
    let reverse = (on & 64) != 0;
    let ex = (on & 128) == 0;
    let all = &stores.allocations;
    match on & 63 {
        2 => {
            // sorted vector: arg = element size in bytes
            let size = arg as u16;
            if reverse {
                let s = vector::sorted_find(&data, ex, size, all, keys, till).0 + u32::from(!ex);
                let f = vector::sorted_find(&data, ex, size, all, keys, from).0 + 1;
                pack_iter(s, f)
            } else {
                let s = vector::sorted_find(&data, true, size, all, keys, from).0;
                let start = if s == 0 { u32::MAX } else { s - 1 };
                let (t, cmp) = vector::sorted_find(&data, ex, size, all, keys, till);
                let finish = if ex || cmp { t } else { t + 1 };
                pack_iter(start, finish)
            }
        }
        1 => {
            // red-black tree / index: arg = fields offset
            let fields = arg as u16;
            let store = crate::keys::store(&data, all);
            if reverse {
                let t = tree::find(&data, ex, fields, all, keys, till);
                let start = if ex {
                    t
                } else {
                    tree::next(store, &iter_ref(&data, t, fields))
                };
                let f = tree::find(&data, ex, fields, all, keys, from);
                let finish = tree::next(store, &iter_ref(&data, f, fields));
                pack_iter(start, finish)
            } else {
                let start = tree::find(&data, true, fields, all, keys, from);
                let t = tree::find(&data, ex, fields, all, keys, till);
                let finish = if ex {
                    t
                } else {
                    tree::previous(store, &iter_ref(&data, t, fields))
                };
                pack_iter(start, finish)
            }
        }
        _ => pack_iter(u32::MAX, u32::MAX),
    }
}

/// Advance the iterator to the next element and return a `DbRef` pointing to it.
/// Returns a `DbRef` with `rec == 0` when iteration is complete.
///
/// `iter` is the mutable `i64` state returned by [`OpIterate`]; it is updated in place.
/// `on` and `arg` must match the corresponding `OpIterate` call.
///
/// Bytecode equivalent: `State::step` in `src/state/io.rs`.
pub fn OpStep(stores: &Stores, iter: &mut i64, data: DbRef, on: i32, arg: i32) -> DbRef {
    let mut cur = (*iter as u64) as u32;
    let mut finish = ((*iter as u64) >> 32) as u32;

    if data.rec == 0 || finish == u32::MAX {
        return stores.element_reference(&data, i32::MAX);
    }

    let reverse = (on & 64) != 0;
    let all = &stores.allocations;

    let result = match on & 63 {
        2 => {
            // sorted vector: arg = element size
            let mut pos = if cur == u32::MAX {
                i32::MAX
            } else {
                #[allow(clippy::cast_possible_wrap)]
                {
                    cur as i32
                }
            };
            if reverse {
                vector::vector_step_rev(&data, &mut pos, all);
                if pos == i32::MAX {
                    finish = u32::MAX;
                }
            } else {
                vector::vector_step(&data, &mut pos, all);
                if pos as u32 >= finish {
                    pos = i32::MAX;
                }
            }
            cur = pos as u32;
            let byte_pos = if pos == i32::MAX {
                i32::MAX
            } else {
                8 + pos * arg
            };
            if pos == i32::MAX {
                finish = u32::MAX;
            }
            stores.element_reference(&data, byte_pos)
        }
        1 => {
            // red-black tree / index: arg = fields offset
            let fields = arg as u16;
            let store = crate::keys::store(&data, all);
            let next_rec = if cur == 0 {
                if reverse {
                    tree::last(&data, fields, all).rec
                } else {
                    tree::first(&data, fields, all).rec
                }
            } else if reverse {
                tree::previous(store, &iter_ref(&data, cur, fields))
            } else {
                tree::next(store, &iter_ref(&data, cur, fields))
            };
            if next_rec == finish {
                finish = u32::MAX;
            }
            cur = next_rec;
            DbRef {
                store_nr: data.store_nr,
                rec: next_rec,
                pos: 8,
            }
        }
        _ => stores.element_reference(&data, i32::MAX),
    };

    *iter = pack_iter(cur, finish);
    result
}

/// Read the entire contents of a file into `content`, replacing its previous value.
/// If the file cannot be opened or read, `content` is cleared.
/// Bytecode equivalent: `State::get_file_text` in `src/state/io.rs`.
pub fn OpGetFileText(stores: &mut Stores, file: DbRef, content: &mut String) {
    if file.rec == 0 {
        return;
    }
    let file_path = {
        let store = stores.store(&file);
        store
            .get_str(store.get_int(file.rec, file.pos + 24) as u32)
            .to_owned()
    };
    content.clear();
    if let Ok(mut f) = File::open(&file_path)
        && f.read_to_string(content).is_err()
    {
        content.clear();
    }
}

/// Seek to `pos` bytes from the start of the file.
/// If the file handle is not yet open, stores `pos` in `#next` so the first
/// read/write applies the seek after opening.
/// Bytecode equivalent: `State::seek_file` in `src/state/io.rs`.
pub fn OpSeekFile(stores: &mut Stores, file: DbRef, pos: i64) {
    if file.rec == 0 {
        return;
    }
    let file_ref = stores.store(&file).get_int(file.rec, file.pos + 28);
    if file_ref == i32::MIN {
        stores
            .store_mut(&file)
            .set_long(file.rec, file.pos + 16, pos);
    } else if let Some(f) = &mut stores.files[file_ref as usize]
        && let Err(e) = f.seek(SeekFrom::Start(pos as u64))
    {
        eprintln!("file seek error: {e}");
    }
}

/// Return the byte size of the file, or `i64::MIN` if the size cannot be determined.
/// Bytecode equivalent: `State::size_file` in `src/state/io.rs`.
#[must_use]
pub fn OpSizeFile(stores: &mut Stores, file: DbRef) -> i64 {
    if file.rec == 0 {
        return i64::MIN;
    }
    let file_path = {
        let store = stores.store(&file);
        store
            .get_str(store.get_int(file.rec, file.pos + 24) as u32)
            .to_owned()
    };
    if let Ok(meta) = std::fs::metadata(&file_path) {
        meta.len() as i64
    } else {
        i64::MIN
    }
}

/// Truncate (or extend) the file to `size` bytes.  Closes any open handle first.
/// Returns `true` on success, `false` on failure.
/// Bytecode equivalent: `State::truncate_file` in `src/state/io.rs`.
pub fn OpTruncateFile(stores: &mut Stores, file: DbRef, size: i64) -> bool {
    if file.rec == 0 {
        return false;
    }
    let file_path = {
        let store = stores.store(&file);
        store
            .get_str(store.get_int(file.rec, file.pos + 24) as u32)
            .to_owned()
    };
    // Close any open handle so resize starts from a clean state.
    let file_ref = stores.store(&file).get_int(file.rec, file.pos + 28);
    if file_ref != i32::MIN && (file_ref as usize) < stores.files.len() {
        stores.files[file_ref as usize] = None;
        stores
            .store_mut(&file)
            .set_int(file.rec, file.pos + 28, i32::MIN);
        stores
            .store_mut(&file)
            .set_long(file.rec, file.pos + 8, i64::MIN);
        stores
            .store_mut(&file)
            .set_long(file.rec, file.pos + 16, i64::MIN);
    }
    OpenOptions::new()
        .write(true)
        .open(&file_path)
        .and_then(|f| f.set_len(size as u64))
        .is_ok()
}

/// Trait allowing `OpRemove` to work with both plain-vector (`i32` index) and
/// sorted/tree (`i64` packed iterator) state variables.
pub trait IterState {
    fn get_cur(&self) -> i32;
    fn set_cur(&mut self, n: i32);
}

impl IterState for i32 {
    fn get_cur(&self) -> i32 {
        *self
    }
    fn set_cur(&mut self, n: i32) {
        *self = n;
    }
}

impl IterState for i64 {
    fn get_cur(&self) -> i32 {
        (*self as u64) as u32 as i32
    }
    fn set_cur(&mut self, n: i32) {
        let finish = (*self as u64) >> 32;
        *self = ((finish << 32) | (n as u32 as u64)) as i64;
    }
}

/// Remove the element at the current iterator position and update the iterator
/// so the next step visits the correct successor.
///
/// - `on & 63 == 0`: plain vector — `arg` is the element type index; size is
///   looked up via `stores.get_type(arg as u16).size`.
/// - `on & 63 == 2`: sorted vector — `arg` is the element size in bytes directly.
///
/// Bytecode equivalent: `State::remove` in `src/state/io.rs`.
pub fn OpRemove<S: IterState>(stores: &mut Stores, state: &mut S, data: DbRef, on: i32, arg: i32) {
    let cur = state.get_cur();
    let reverse = (on & 64) != 0;
    match on & 63 {
        0 => {
            // plain vector: arg is the element type index
            let elem_size = u32::from(stores.size(arg as u16));
            let n = if reverse { cur + 1 } else { cur - 1 };
            vector::remove_vector(&data, elem_size, cur, &mut stores.allocations);
            state.set_cur(n);
        }
        2 => {
            // sorted vector: arg is the element size in bytes
            if cur < 0 {
                return;
            }
            let n = if reverse { cur + 1 } else { cur - 1 };
            vector::remove_vector(&data, arg as u32, cur, &mut stores.allocations);
            state.set_cur(n);
        }
        _ => {}
    }
}

/// Remove a record from a hash or index collection.
///
/// Bytecode equivalent: `State::hash_remove` in `src/state/io.rs`.
pub fn OpHashRemove(stores: &mut Stores, data: DbRef, rec: DbRef, tp: i32) {
    if rec.rec != 0 {
        stores.remove(&data, &rec, tp as u16);
    }
}

/// Append `count - 1` copies of the last element of `data`, expanding the vector.
///
/// Bytecode equivalent: `State::append_copy` in `src/state/io.rs`.
pub fn OpAppendCopy(stores: &mut Stores, data: DbRef, count: i32, tp: i32) {
    let ctp = stores.content(tp as u16);
    let size = u32::from(stores.size(ctp));
    let length = vector::length_vector(&data, &stores.allocations) as u32;
    // Read v_rec before resize; from points to the last existing element.
    let v_rec_before = crate::keys::store(&data, &stores.allocations)
        .get_int(data.rec, data.pos) as u32;
    let from = DbRef {
        store_nr: data.store_nr,
        rec: v_rec_before,
        pos: 8 + (length * size - size),
    };
    let multiply = count as u32;
    // Resize to accommodate `multiply` additional elements.
    vector::vector_append(&data, size, &mut stores.allocations);
    stores.vector_set_size(&data, multiply, size);
    // Re-read v_rec in case the resize moved the record.
    let v_rec = crate::keys::store(&data, &stores.allocations)
        .get_int(data.rec, data.pos) as u32;
    for i in 0..(multiply - 1) {
        let to = DbRef {
            store_nr: data.store_nr,
            rec: v_rec,
            pos: 8 + (length + i) * size,
        };
        stores.copy_block(&from, &to, size);
        stores.copy_claims(&data, &to, ctp);
    }
}
